// friday13.cs — Friday the 13th experiments with proleptic Gregorian calendar

// Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
DateTime? earliest = null;

while (date.Year == 1)
{
    if (date.DayOfWeek == DayOfWeek.Friday)
    {
        earliest = date;
        break;
    }
    date = date.AddMonths(1);
}

// If not found in year 1, keep searching (unlikely but safe)
if (earliest is null)
{
    date = new DateTime(2, 1, 13);
    while (earliest is null)
    {
        if (date.DayOfWeek == DayOfWeek.Friday)
            earliest = date;
        else
            date = date.AddMonths(1);
    }
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd} ({earliest:dddd, MMMM d, yyyy})");
Console.WriteLine();

// Count Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
var counts = new Dictionary<int, int>(); // month -> count

for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateTime(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            count++;
            counts[month] = counts.GetValueOrDefault(month) + 1;
        }
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");
Console.WriteLine();

Console.WriteLine("Distribution by month:");
for (int m = 1; m <= 12; m++)
{
    var name = new DateTime(2000, m, 1).ToString("MMMM");
    Console.WriteLine($"  {name,-12} {counts.GetValueOrDefault(m),3}");
}

// Bonus: which day of the week is most likely to be the 13th?
Console.WriteLine();
Console.WriteLine("Day-of-week distribution for the 13th (400-year cycle):");
var dowCounts = new int[7];
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateTime(year, month, 13);
        dowCounts[(int)d.DayOfWeek]++;
    }
}

for (int i = 0; i < 7; i++)
{
    Console.WriteLine($"  {(DayOfWeek)i,-12} {dowCounts[i],4}");
}

